target:
::-webkit-scrollbar {
  width: 8px;
}
::-webkit-scrollbar-track {
  background: var(--bg-dark);
}
::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.15);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.3);
}

replacement:
::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, var(--forest-light), var(--leaf-morning), var(--gold-light));
  border-radius: 10px;
  box-shadow: 0 0 6px var(--leaf-morning);
}
::-webkit-scrollbar-thumb:hover {
  background: linear-gradient(180deg, var(--leaf-morning), var(--gold-light));
  box-shadow: 0 0 10px var(--gold-light);
}
